            let mut name_bytes: &[u8] = b"?";
            let kind = get_obj_name(p, pc, instr.arg_a() as i32, &mut name_bytes);
            *name = Some(name_bytes.to_vec());
            kind
        }
        // C: case OP_TFORCALL: *name = "for iterator"; return "for iterator";
        OpCode::TForCall => {
            *name = Some(b"for iterator".to_vec());
