    let mut p = top;
    while p.0 > func_idx.0 {
        let val = state.get_at(p - 1).clone();
        state.set_at(p, val);
        p = p - 1;
    }
    // C: L->top.p++
    state.set_top(top + 1);
    // C: setobj2s(L, func, tm)
    state.set_at(func_idx, tm);

    Ok(func_idx)
}

